      };
      mega-anime.enable = true;

      # gitea + postgres + readaloud are upstream/flake-input modules.
      # Wrap-data registers them on the dashboard; host-specific config
      # (postgres backend, readaloud paths) stays here.
      gitea = {
        enable = true;
        settings.database.type = "postgres";
      };
      postgresql = {
        enable = true;
        ensureDatabases = [ "gitea" ];
        ensureUsers = [
          {
            name = "gitea";
            ensureDBOwnership = true;
          }
        ];
      };
      readaloud = {
        enable = true;
        host = "pylon";
        dataDir = "/var/lib/readaloud/data";
        localaiUrl = "http://phanteks:8090";
        secretKeyBaseFile = "/run/agenix/readaloud-secret-key";
      };

      # Dashboard: just enable. Cross-host registrations flow via
      # inputs.self.aggregatedRegistrations (flake-managed hosts) +
      # `external = true;` wraps in nix/services/wraps.nix (services
      # on hosts this flake doesn't manage at the NixOS level).
      dashboard.enable = true;
    };

    # Service-specific ports come from their own modules via openFirewall
    # or networking.firewall.allowedTCPPorts. Only host-specific ports
    # without an openFirewall option go here.
    networking.firewall = {
      enable = true;
      allowedTCPPorts = [
        3000 # gitea
        4000 # readaloud
      ];
    };
  };
}

